parameters.jsCode:
// 1. Dohvatite stvarni niz povijesti poruka
// Na temelju vašeg izlaza, niz poruka se nalazi pod ključem 'history'
// unutar prvog elementa izlaza HTTP Request čvora.
const httpResponse = $input.first().json;
const historyArray = httpResponse.history;

// Email adrese: Vaša (Mindaptive) adresa i adresa prospekta
// Koristimo email adrese iz prve poruke kao referencu
const yourEmail = historyArray[0].from; // "mia@mindaptivedeep.com" 
const prospectEmail = historyArray[0].to; // "mindaptive@gmail.com" 

// 2. Funkcija za čišćenje HTML-a i uklanjanje citiranih (quoted) dijelova
function cleanEmailBody(html) {
    if (!html) return "";

    // A. Uklonite citirane (quoted) dijelove (sve nakon prve <div class="gmail_quote)
    const quoteIndex = html.indexOf('<div class="gmail_quote');
    if (quoteIndex !== -1) {
        html = html.substring(0, quoteIndex);
    }
    // Drugi način uklanjanja citiranih dijelova koji je sigurniji:
    const altQuoteIndex = html.indexOf('<blockquote class="gmail_quote"');
    if (altQuoteIndex !== -1) {
        html = html.substring(0, altQuoteIndex);
    }

    // B. Uklonite HTML tagove regex-om (može ostaviti višak razmaka, ali je brzo)
    let text = html.replace(/<[^>]*>/g, '');

    // C. Uklonite višak praznih linija i razmaka
    text = text.replace(/(\n\s*){3,}/g, '\n\n'); // Zamjenjuje 3+ prazne linije s dvije
    text = text.trim();

    return text;
}

// 3. Kreiranje formatiranog stringa za OpenAI
let formattedHistory = "--- FULL CONVERSATION HISTORY ---\n\n";

if (Array.isArray(historyArray)) {
    // Sortirajte poruke po datumu, iako SmartLead obično vraća ispravan redoslijed
    // Ostavljamo ih u originalnom redoslijedu jer SmartLead obično vraća starije poruke prve

    historyArray.forEach((message, index) => {
        const type = message.type; // SENT ili REPLY 
        const senderAddress = message.from; // Adresa pošiljatelja 
        const rawContent = message.email_body; // Sadržaj poruke (HTML) 
        const time = new Date(message.time).toLocaleString('en-US', { timeZone: 'Europe/Zagreb' }); // Formatiranje vremena

        // Odredite tko je poslao poruku
        let senderName;
        if (type === 'SENT' && senderAddress === yourEmail) {
            senderName = "MINDAPTIVE (Your Agent)";
        } else if (type === 'REPLY' && senderAddress === prospectEmail) {
            senderName = "PROSPECT (Lead)";
        } else {
            // Ako je REPLY, ali nije adresa prospekta, provjerite tko je zapravo poslao.
            // U SmartLeadu, REPLY su odgovori prospekta, ali je dobro biti siguran.
            senderName = (senderAddress === yourEmail) ? "MINDAPTIVE (Your Agent)" : "PROSPECT (Lead)";
        }

        const cleanedContent = cleanEmailBody(rawContent);

        // Dodavanje poruke u string
        formattedHistory += `--- MESSAGE ${index + 1} (${time}) ---\n`;
        formattedHistory += `SENDER: ${senderName}\n`;
        formattedHistory += `CONTENT:\n${cleanedContent}\n\n`;
    });
} else {
    formattedHistory += "ERROR: SmartLead API did not return a valid message history array.\n";
}

formattedHistory += "--- END OF HISTORY ---\n";


// 4. Vratite novi objekt s formatiranom povijesti
return [
    {
        json: {
            // Ostavljamo sve postojeće podatke
            ...httpResponse, 
            // Dodajemo novi ključ s formatiranom povijesti
            chat_history_text: formattedHistory
        }
    }
];

